generated_oml:
// Physical sensors and data transmission
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Permanent magnet synchronous motor current sensor (I_M)"
    DTDFVocab:producedData MotorCurrentDataTransmitted
]

instance MotorPositionEncoder : DTDFVocab:SensingComponent [
    base:desc "Position encoder on motor shaft to sense motor angle"
    DTDFVocab:producedData MotorPositionDataTransmitted
]

instance GearboxPositionEncoder : DTDFVocab:SensingComponent [
    base:desc "Position encoder on gearbox output shaft to sense gearbox angle"
    DTDFVocab:producedData GearboxPositionDataTransmitted
]

instance MotorCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance MotorPositionDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorPositionEncoder
]

instance GearboxPositionDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxPositionEncoder
]

// Live data streams
instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Live motor current data stream I_M from sensor via MQTT"
    DTDFVocab:fromData MotorCurrentDataTransmitted
    DTDFVocab:inputTo MQTTPublisherBroker, MATLABSimulinkEngine
]

instance MotorPositionData : DTDFVocab:Data [
    base:desc "Live motor angular position from encoder via MQTT"
    DTDFVocab:fromData MotorPositionDataTransmitted
    DTDFVocab:inputTo MQTTPublisherBroker, MATLABSimulinkEngine
]

instance GearboxPositionData : DTDFVocab:Data [
    base:desc "Live gearbox angular position from encoder via MQTT"
    DTDFVocab:fromData GearboxPositionDataTransmitted
    DTDFVocab:inputTo MQTTPublisherBroker, MATLABSimulinkEngine
]

instance DerivedTorqueData : DTDFVocab:Data [
    base:desc "Derived torque from current and position data"
    DTDFVocab:inputTo MATLABSimulinkEngine
]

instance AngularVelocityData : DTDFVocab:Data [
    base:desc "Derived angular velocity from position sensors"
    DTDFVocab:inputTo MATLABSimulinkEngine
]

instance AccelerationData : DTDFVocab:Data [
    base:desc "Derived angular acceleration from velocity data"
    DTDFVocab:inputTo MATLABSimulinkEngine
]

// Simulated data streams
instance SimulatedMotorCurrentData : DTDFVocab:Data [
    base:desc "Simulated motor current from Simulink motor model"
    DTDFVocab:inputTo MATLABSimulinkEngine
]

instance SimulatedMotorPositionData : DTDFVocab:Data [
    base:desc "Simulated motor position from Simulink motor model"
    DTDFVocab:inputTo MATLABSimulinkEngine
]

instance SimulatedGearboxPositionData : DTDFVocab:Data [
    base:desc "Simulated gearbox position from Simulink gearbox model"
    DTDFVocab:inputTo MATLABSimulinkEngine
]

// Simulation models
instance MotorSimulinkModel : DTDFVocab:Model [
    base:desc "Matlab Simulink model of motor dynamics including torque input"
    DTDFVocab:inputTo MATLABSimulinkEngine
]

instance GearboxSimulinkModel : DTDFVocab:Model [
    base:desc "Matlab Simulink model of gearbox dynamics including gear ratio and losses"
    DTDFVocab:inputTo MATLABSimulinkEngine
]

instance FrictionModelCoulombViscous : DTDFVocab:Model [
    base:desc "Coulomb–Viscous friction model instance for motor shaft slip"
    DTDFVocab:inputTo MATLABSimulinkEngine
]

instance FrictionModelStribeck : DTDFVocab:Model [
    base:desc "Stribeck friction model instance for high‑speed slip conditions"
    DTDFVocab:inputTo MATLABSimulinkEngine
]

instance FrictionModelDahl : DTDFVocab:Model [
    base:desc "Dahl friction model instance representing stick‑slip"
    DTDFVocab:inputTo MATLABSimulinkEngine
]

instance FrictionModelLuGre : DTDFVocab:Model [
    base:desc "LuGre friction model instance for comprehensive friction dynamics"
    DTDFVocab:inputTo MATLABSimulinkEngine
]

// Enablers (tools & infrastructure)
instance SysMLModelingTool : DTDFVocab:Enabler [
    base:desc "SysML tool used to define structural and behavioral models of the first axis"
]

instance MATLABSimulinkEngine : DTDFVocab:Enabler [
    base:desc "MATLAB Simulink engine used to execute simulation models"
    DTDFVocab:enables SimulationDeviationService, FrictionIdentificationService
]

instance MQTTPublisherBroker : DTDFVocab:Enabler [
    base:desc "MQTT broker for streaming live sensor data from physical to virtual twin"
    DTDFVocab:enables RealTimeDashboardService, DataAggregationService
]

instance AssetAdministrationShell : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell providing digital asset identity and metadata for the first axis"
]

instance DashboardPlatform : DTDFVocab:Enabler [
    base:desc "Dashboard platform for real‑time visualization and monitoring of twin data"
    DTDFVocab:enables RealTimeDashboardService
]

// Insights
instance FrictionInsight : DTDFVocab:Insight [
    base:desc "Real‑time friction insights derived from comparison of live torque data with simulated friction model outputs"
]

instance ControllerParameterAdjustmentInsight : DTDFVocab:Insight [
    base:desc "Insights used to adjust robot controller parameters based on updated friction model"
]

instance ModelDeviationInsight : DTDFVocab:Insight [
    base:desc "Insight indicating deviation between simulated and live outputs to assess model fidelity"
]

instance DashboardVisualizationInsight : DTDFVocab:Insight [
    base:desc "Insight for dashboard visualization of real and simulated data"
]

instance DataAggregatedInsight : DTDFVocab:Insight [
    base:desc "Insight summarizing aggregated data streams for higher‑level analysis"
]

// Action
instance UpdateFrictionParametersAction : DTDFVocab:Action [
    base:desc "Automatically updates friction model parameters within the simulation models using identified values"
    DTDFVocab:IsAutomatic true
]

// Services
instance RealTimeDashboardService : DTDFVocab:Service [
    base:desc "Real‑time visualization dashboard displaying live sensor data, simulated outputs, and friction parameter updates"
    DTDFVocab:provides DashboardVisualizationInsight
]

instance DataAggregationService : DTDFVocab:Service [
    base:desc "Aggregates live data streams from MQTT broker for further analysis and model evaluation"
    DTDFVocab:provides DataAggregatedInsight
]

instance FrictionIdentificationService : DTDFVocab:Service [
    base:desc "Continuously identifies friction model parameters (white‑box and black‑box) based on live data and simulation comparison"
    DTDFVocab:provides FrictionInsight, UpdateFrictionParametersAction
]

instance SimulationDeviationService : DTDFVocab:Service [
    base:desc "Compares simulated outputs to live data streams to measure deviation and assess model fidelity"
    DTDFVocab:provides ModelDeviationInsight
]

instance FrictionParameterUpdateService : DTDFVocab:Service [
    base:desc "Updates friction model parameters within simulation models to improve motion accuracy"
    DTDFVocab:provides UpdateFrictionParametersAction
]

// Physical asset
instance MABIMAX100FirstAxisAsset : DTDFVocab:Component [
    base:desc "First axis of the MABI MAX 100 industrial robot"
]

// Digital Twin Environment
instance FirstAxisDigitalTwin : DTDFVocab:DigitalTwin [
    base:contains MotorCurrentSensor, MotorPositionEncoder, GearboxPositionEncoder,
             MotorCurrentDataTransmitted, MotorPositionDataTransmitted, GearboxPositionDataTransmitted,
             MotorCurrentData, MotorPositionData, GearboxPositionData, DerivedTorqueData,
             AngularVelocityData, AccelerationData, SimulatedMotorCurrentData,
             SimulatedMotorPositionData, SimulatedGearboxPositionData,
             MotorSimulinkModel, GearboxSimulinkModel, FrictionModelCoulombViscous,
             FrictionModelStribeck, FrictionModelDahl, FrictionModelLuGre,
             MABIMAX100FirstAxisAsset
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "None; the digital shadow does not send control commands to PT in this implementation."
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Continuous real‑time data interchange; synchronization aligned with robot operation; data streaming at sensor sampling rate (not specified), simulations executed in real‑time to match live data."
]

