    base:desc "MQTT protocol used for real‑time data transfer between PT and DT; AAS for asset metadata; possible use of SysML tools for model exchange; no explicit network topology defined."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Use of SysML for modeling; AAS standard for asset administration; reference model DSRM; utilization of ISO/IEC standards for digital twin reference but not specified."
]

